class Solution:
    def nextGreaterElement(self, nums1, nums2):
        res = []
        for x in nums1:
            idx = nums2.index(x)
            nxt = -1
            for j in range(idx + 1, len(nums2)):
                if nums2[j] > x:
                    nxt = nums2[j]
                    break
            res.append(nxt)
        return res

