var nextGreaterElement = function(nums1, nums2) {
    const nxt = new Map();
    const stack = [];
    for (const x of nums2) {
        while (stack.length && x > stack[stack.length - 1]) {
            nxt.set(stack.pop(), x);
        }
        stack.push(x);
    }
    return nums1.map(x => nxt.has(x) ? nxt.get(x) : -1);
};
